export function CollapseDemo() {
    return (
        <>
            <Section title="Real use · FAQ (exclusive — one open at a time)">
                <div className="flex max-w-md flex-col gap-2">
                    {FAQS.map((f, i) => (
                        <Collapse key={f.q} name="faq" open={i === 0}>
